  9	  FormGroup,
 10	  FormGroupProps,
 11	  InputGroup,
 12	  TextInput,
 13	  Popover,
 14	  PopoverProps,
 15	  PopoverPosition,
 16	  HelperText,
 17	  HelperTextItem,
 18	  Button,
 19	  TextInputProps,
 20	  Icon,
 21	  FormHelperText,
 22	  HelperTextItemProps,
 23	} from '@patternfly/react-core';
 24	import useFieldRequirements from './useFieldRequirements';
 25	import './TextInputWithFieldRequirements.scss';
 26	
 27	export type TextInputWithFieldRequirementsProps = {
 28	  fieldRequirements: string[];
 29	  control: Control<FieldValues>;
 30	  defaultValue?: any;
 31	  formGroupProps: FormGroupProps;
 32	  // In PF5 FormGroupProps don't have helperText
 33	  helperText?: string;
 34	  textInputProps: TextInputProps & {
 35	    'data-test': string;
 36	    disabled?: boolean;
 37	  };
 38	  popoverProps: Omit<PopoverProps, 'bodyContent'>;
 39	  infoElement?: JSX.Element;
 40	  inputPrefixElement?: JSX.Element;
 41	};
 42	
 43	export type ValidationIconProp = {
 44	  status: HelperTextItemProps['variant'];
 45	};
 46	
 47	export const getStatusIcon = (status: string) => {
 48	  switch (status) {
 49	    case 'error':
 50	      return <ExclamationCircleIcon />;
 51	    case 'success':
 52	      return <CheckCircleIcon />;
 53	
 54	    default:
 55	      return <InfoCircleIcon />;
 56	  }
 57	};
 58	
 59	const getVariant = (status: string) => {
 60	  switch (status) {
 61	    case 'error':
 62	      return 'danger';
 63	    case 'success':
 64	      return 'success';
 65	    default:
 66	      return 'info';
 67	  }
 68	};
 69	
 70	const TextInputWithFieldRequirements: React.FC<
 71	  TextInputWithFieldRequirementsProps
 72	> = ({
 73	  fieldRequirements,
 74	  control,
 75	  formGroupProps,
 76	  textInputProps,
 77	  popoverProps,
 78	  defaultValue = '',
 79	  helperText,
 80	  infoElement,
 81	  inputPrefixElement,
 82	}) => {
 83	  const {
 84	    field: { name, value, onChange, onBlur },
 85	    fieldState: { error, isDirty, isTouched },
 86	    formState: { isSubmitted },
 87	  } = useController({
 88	    name: textInputProps.name || 'name',
 89	    control,
 90	    defaultValue: defaultValue,
 91	  });
 92	  const state = useFieldRequirements(
 93	    fieldRequirements,
 94	    isDirty || isSubmitted,
 95	    error
 96	  );
 97	  const [isVisible, setIsVisible] = React.useState(false);
 98	  const [validated, setValidated] =
 99	    React.useState<HelperTextItemProps['variant']>('default');
100	
101	  React.useEffect(() => {
102	    setValidated(
103	      isDirty || isTouched || isSubmitted
104	        ? error
105	          ? 'error'
106	          : 'success'
107	        : 'default'
108	    );
109	  }, [error, isDirty, isTouched, isSubmitted]);
110	
111	  const handleInputChange = React.useCallback(
112	    (event: React.FormEvent<HTMLInputElement>, newValue: string) => {
113	      if (!isVisible) setIsVisible(true);
114	      textInputProps?.onChange?.(event, newValue);
115	      onChange(newValue, event);
116	    },
117	    [isVisible, onChange, textInputProps]
118	  );
119	
120	  const handleInputBlur = React.useCallback(
121	    (event: React.FormEvent<HTMLInputElement>) => {
122	      setIsVisible(false);
123	      textInputProps?.onBlur?.(event);
124	      onBlur();
125	    },
126	    [onBlur, textInputProps]
127	  );
128	
129	  return (
130	    <FormGroup {...formGroupProps}>
131	      {infoElement}
132	      <div className="field-requirements-input-section">
133	        {inputPrefixElement}
134	        <InputGroup
135	          data-test="field-requirements-input-group"
136	          className={cn(
137	            'rich-input__group',
138	            error && 'rich-input__group--invalid',
139	            !error && (isDirty || isSubmitted) && 'rich-input__group--success'
140	          )}
141	        >
142	          <InputGroupItem isFill>
143	            <TextInput
144	              {...textInputProps}
145	              name={name}
146	              value={value}
147	              className={cn('rich-input__text', textInputProps?.className)}
148	              onBlur={handleInputBlur}
149	              onFocus={() => setIsVisible(true)}
150	              onClick={() => setIsVisible(true)}
151	              onChange={handleInputChange}
152	              onKeyUp={onBlur /*Required for avoiding outdated validations.*/}
153	            />
154	          </InputGroupItem>
155	          <InputGroupItem>
156	            <Popover
157	              data-test="field-requirements-popover"
158	              position={PopoverPosition.top}
159	              isVisible={isVisible}
160	              shouldOpen={() => setIsVisible(true)}
161	              shouldClose={() => setIsVisible(false)}
162	              bodyContent={
163	                <HelperText component="ul">
164	                  {Object.keys(state.fieldRequirements).map((rule) => {
165	                    return (
166	                      <HelperTextItem
167	
168	                        variant={state.fieldRequirements[rule]}
169	                        component="li"
170	                        key={rule}
171	                      >
172	                        {rule}
173	                      </HelperTextItem>
174	                    );
175	                  })}
176	                </HelperText>
177	              }
178	              withFocusTrap={false}
179	              {...popoverProps}
180	            >
181	              <Button variant="plain" aria-label="Validation" tabIndex={-1}>
182	                <Icon status={getVariant(validated)}>
183	                  {getStatusIcon(validated)}
184	                </Icon>
185	              </Button>
186	            </Popover>
187	          </InputGroupItem>
188	        </InputGroup>
189	      </div>
190	      <FormHelperText>
191	        <HelperText>
192	          <HelperTextItem variant={validated}>{helperText}</HelperTextItem>
193	        </HelperText>
194	      </FormHelperText>
195	    </FormGroup>
196	  );
197	};
198	
199	export default TextInputWithFieldRequirements;

